//opening the .midi file and getting the whole content into a char array for later// analysis.// Mac version#include "stdio.h"#include "openmidfilemac.h"#include "muMIDIplayer.h"OSErr fOSErr;Handle gMidiBuf; // Handle to the raw midi buffer data read from a filestatic short gFileNum; //file number for opened .mid filestatic long gFileSize; //keeps track of how many bytes in the file//entry function for one stop shop in a midi player type environment//returns -1 for generic errors//returns -2 if the MTHd string can't be found inside the midi file //returns -3 for out of memory during handle allocation  int midiDialogLoadAndPrep(void){int indexStart=0;  //MThd should be at position 0, but it might not, so we'll find itindexStart = getAndAnalyzeMIDI(); //will ask for a midi file and get its basic infoif(indexStart < 0) return indexStart;//routines from muMIDIPlayer.c		initSMF(); //default values for midi record				readSMFHeader((int)indexStart); //get the actual values for midi recordallocateTracks(); //get the starters and parsers all readypreProcessEvents();primeMidiFaster(); //will HLock processedEvents//you can now use playmidi_faster in your loop to play it}//function that loads a known file directly in the same directory as the program//TODO//functions that loads an embedded DATA resource in the app directly//TODO//directs the reading and parsing of the MIDI file//returns -1 for generic errors//returns -2 if the MTHd string can't be found inside the midi file     int getAndAnalyzeMIDI(void)	{	int indexToStart=0; //MThd should be at position 0, but it might not, so we'll find it		gFileNum = openMIDIFile(); //actual process of asking for a midi file through std mac dialog	if(gFileNum < 0) return gFileNum; //an error happen, do nothing else		indexToStart = findPositionOfHeader(); //find the start index of 'MThd'	if(indexToStart == -1) return -2;		return indexToStart;	}//this finds the start position of the 'MThd' string//returns -1 if it can't find it	int findPositionOfHeader(void)	{	char targetSequence[] = "MThd";    char *position;    int thePosition = 0;        HLock((Handle)gMidiBuf);    position = (char *)strstr(*gMidiBuf, targetSequence);		if(position != NULL)		{		thePosition = (position - *gMidiBuf);    	HUnlock((Handle)gMidiBuf);		return thePosition;		}	    HUnlock((Handle)gMidiBuf);	return -1;	}	//opens a MID, MIDI or Midi file through the std File dialog//returns -1 if there's an error. Inspect fOSErr with your own code if you wish//returns -3 for out of memory during handle allocationshort openMIDIFile(void)	{  	SFReply reply; /* used in file operations */  	SFTypeList myTypes; /* used in file operations */  	Point where = {50,50}; /* top left corner of Std file window */  	myTypes[0]='MIDI';   /* Those are the possible file type codes */  	myTypes[1]='MID ';   /* no idea if this one is used, but let's put it for good measure */  	myTypes[2]='Midi';   /* I've seen those too sometimes */    	SFGetFile(where,"\pSelect a MIDI file",0L,1,myTypes,0L,&reply);  	if(reply.good)    	{    	fOSErr = FSOpen(reply.fName,reply.vRefNum,&gFileNum);    	if(fOSErr != noErr) return -1;     	else     		{    		fOSErr = GetEOF(gFileNum, &gFileSize);    		if(fOSErr != noErr) return -1;    		else     			{    			if(gMidiBuf != NULL) DisposHandle((Handle)gMidiBuf);    			gMidiBuf = (char **) NewHandle(gFileSize);    			if(gMidiBuf == NULL) return -3; //out of memory    			    			HLock((Handle)gMidiBuf);    			fOSErr = FSRead(gFileNum, &gFileSize, *gMidiBuf);    			HUnlock((Handle)gMidiBuf);    			    			if(fOSErr != noErr)    				{    				DisposHandle(gMidiBuf);    				FSClose(gFileNum);    				return -1;    				}    			FSClose(gFileNum);    			return gFileNum; //the good scenario happens here    			}    		}    	}    return -1; //either there's a mistake in the file dialog fetching routine, or no file was selected	}	